using System;
using System.Collections.Generic;
using System.Text.Json;
using System.Text.Json.Serialization;

namespace Azure.ResourceManager
{
    internal class ResponseErrorConverter : JsonConverter<ResponseError>
    {
        public override ResponseError Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
        {
            using var document = JsonDocument.ParseValue(ref reader);
            return ReadResponseError(document.RootElement);
        }

        private static ResponseError ReadResponseError(JsonElement element)
        {
            if (element.ValueKind == JsonValueKind.Null)
            {
                return null;
            }

            string code = null;
            string message = null;
            string target = null;
            ResponseInnerError innerError = null;
            IReadOnlyList<ResponseError> details = null;
            JsonElement additionalInfo = default;

            foreach (var property in element.EnumerateObject())
            {
                if (property.NameEquals("code"u8))
                {
